window.__QUIZ_DATA__=[{"id":"objective>Computer Studies>2024>1","subject":"Computer Studies","year":"2024","type":"Objective","topic":"BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE","question":"An automatic system is one that","images":[],"options":{"A":"is operated using sophisticated skills","B":"needs fuel before it can be operated by humans","C":"performs different kinds of tasks diligently","D":"requires little or no human intervention to work"},"answer":"D","explanation":"An automatic system is one that operates independently, without human intervention, once it is set in motion. It performs tasks on its own, without the need for continuous human control or input.  Automatic systems are designed to reduce human labor, increase efficiency, and improve accuracy, making them essential in various industries, such as manufacturing, transportation, and healthcare.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2024>2","subject":"Computer Studies","year":"2024","type":"Objective","topic":"INFORMATION AGE : DATA AND INFORMATION","question":"Which of the following features of information is not important for meaningful decision?","images":[],"options":{"A":"Accuracy","B":"Competitiveness","C":"Completeness","D":"Timeliness"},"answer":"B","explanation":"Competitiveness is not a feature of information itself, but rather a aspect of business or organizational strategy.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2024>3","subject":"Computer Studies","year":"2024","type":"Objective","topic":"TOOLS FOR PROCESSING INFORMATION : OPERATING SYSTEM","question":"The microprocessor that controls a washing machine is known as:","images":[],"options":{"A":"bot","B":"console","C":"embedded computer","D":"mainframe computer"},"answer":"C","explanation":"An embedded computer is a small, specialized computer system that is built into a device or system to control its functions. In the case of a washing machine, the embedded computer controls the machine's cycles, temperature, and other functions.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2024>4","subject":"Computer Studies","year":"2024","type":"Objective","topic":"INFORMATION AGE : DATA AND INFORMATION","question":"Which of the following statements is correct about data?","images":[],"options":{"A":"Information is a product of data while knowledge is a product of information","B":"Data produces knowledge while knowledge produces information","C":"Data is a product of information while knowledge is a product of data","D":"Knowledge produces information while information produces data"},"answer":"A","explanation":"The correct sequence is:    Data \u2192 Information \u2192 Knowledge    Data is processed and organized to create information, which is then analyzed and applied to gain knowledge.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2024>5","subject":"Computer Studies","year":"2024","type":"Objective","topic":"BASIC COMPUTING : CLASSIFICATION OF COMPUTERS~~INFORMATION AGE : HISTORY OF COMPUTERS","question":"Instructions were written to the first generation computers in","images":[],"options":{"A":"assemblers","B":"low level language","C":"machine language","D":"mnemonics"},"answer":"C","explanation":"The first generation computers (1940s-1950s) were programmed using machine language, which consists of binary code (0s and 1s) that the computer's processor can execute directly. Programmers had to write instructions using machine language, which was a tedious and error-prone process.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2024>6","subject":"Computer Studies","year":"2024","type":"Objective","topic":"INFORMATION AGE : HISTORY OF COMPUTERS","question":"Addition and subtraction of numbers in Abacus are done using","images":[],"options":{"A":"bars","B":"beads","C":"frame","D":"string"},"answer":"B","explanation":"An Abacus is a traditional calculating tool used for arithmetic calculations. It consists of a frame with rows of beads on wires. The beads are used to represent numbers and perform calculations.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2024>7","subject":"Computer Studies","year":"2024","type":"Objective","topic":"INFORMATION AGE : HISTORY OF COMPUTERS","question":"In the slide rule, multiplication that goes off the scale can be corrected by the following approaches except","images":[],"options":{"A":"resetting the slide","B":"using circular slide rule","C":"using flat scales","D":"using folded scales"},"answer":"C","explanation":"using flat scales is not a method to correct multiplication that goes off the scale on a slide rule.    Here are the methods that can be used:    Resetting the slide: If the product goes off the scale on one side, you can often reset the slide and continue the calculation on the other side.  Using a circular slide rule: Circular slide rules can handle larger numbers and calculations that might go off the scale on a flat slide rule.  Using folded scales: Some slide rules have folded scales that allow for calculations with larger numbers.  Therefore, using flat scales is not a valid approach for correcting multiplication that goes off the scale.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2024>8","subject":"Computer Studies","year":"2024","type":"Objective","topic":"BASIC COMPUTING : COMPONENTS OF COMPUTERS","question":"The computer's short-term memory is the","images":[],"options":{"A":"arithmetic logic unit","B":"arithmetic operator","C":"control unit","D":"random access memory"},"answer":"D","explanation":"Random Access Memory (RAM) is the computer's short-term memory, where data and program instructions are stored temporarily while being processed. RAM allows the computer to access and manipulate data quickly, but its contents are lost when the computer is powered off.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2024>9","subject":"Computer Studies","year":"2024","type":"Objective","topic":"LOGIC GATES","question":"Which of the following logic devices is considered as  equivalent gate ?","images":[],"options":{"A":"AND","B":"EX-NOR","C":"EX-OR","D":"NOR"},"answer":"B","explanation":"EX-NOR is considered an equivalent gate.    An equivalent gate is a logic gate that can perform the same function as another gate or combination of gates. The EX-NOR (Exclusive NOR) gate is equivalent to the AND gate followed by a NOT gate. In other words, the output of an EX-NOR gate is 1 only when both inputs are the same (either both 0 or both 1). This is the same behavior as an AND gate followed by a NOT gate.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2024>10","subject":"Computer Studies","year":"2024","type":"Objective","topic":"LOGIC GATES","question":"Use the devices in Figure 1 and Figure 2 to answer questions 10 to 13. given that the input variables X and Y have values of 0011 and 0101 respectively as shown on Table 1            Compute the value of the output Z in Figure 1 using the values of X and Y given.","images":["data:image/jpeg;base64,","data:image/jpeg;base64,"],"options":{"A":"0001","B":"0110","C":"0111","D":"1000"},"answer":"C","explanation":"The gate is OR Gate    XYZ = X + Y000011101111","marks":"1","difficulty":"3"},{"id":"objective>Computer Studies>2024>11","subject":"Computer Studies","year":"2024","type":"Objective","topic":"LOGIC GATES","question":"Use the devices in Figure 1 and Figure 2 to answer questions 10 to 13. given that the input variables X and Y have values of 0011 and 0101 respectively as shown on Table 1            If the input variable X in Figure 1 is passed through the device in Figure 2 before going into the logic gate in Figure 1, what will be the value of the output Z?","images":["data:image/jpeg;base64,","data:image/jpeg;base64,"],"options":{"A":"0111","B":"1011","C":"1101","D":"1110"},"answer":"C","explanation":"The gate in Figure 2 is NOT gate. When X passes through it, X becomes:   X  = 1100    XY X Z =  X  + Y0011011110001101","marks":"1","difficulty":"3"},{"id":"objective>Computer Studies>2024>12","subject":"Computer Studies","year":"2024","type":"Objective","topic":"LOGIC GATES","question":"Use the devices in Figure 1 and Figure 2 to answer questions 10 to 13. given that the input variables X and Y have values of 0011 and 0101 respectively as shown on Table 1            If the input variable Y in Figure 1 is passed through the device in Figure 2 before going into the logic gate in Figure 1, compute the resulting output Z?","images":["data:image/jpeg;base64,","data:image/jpeg;base64,"],"options":{"A":"0111","B":"1011","C":"1101","D":"1110"},"answer":"B","explanation":"NOT Y = 1010  X +  Y  = 0011 + 1010    XY Y Z = X +  Y 0011010010111101","marks":"1","difficulty":"3"},{"id":"objective>Computer Studies>2024>13","subject":"Computer Studies","year":"2024","type":"Objective","topic":"LOGIC GATES","question":"Use the devices in Figure 1 and Figure 2 to answer questions 10 to 13. given that the input variables X and Y have values of 0011 and 0101 respectively as shown on Table 1            Using the given values X and Y for the device in Figure 1, what will be the output Z if it is passed through the device in Figure 2","images":["data:image/jpeg;base64,","data:image/jpeg;base64,"],"options":{"A":"0001","B":"0110","C":"0111","D":"1000"},"answer":"D","explanation":"X + Y = Z  0011 + 0101 = 0111  If the result is passed through the NOT gate, it becomes:   Z  = 1000    XYZ = X + Y Z 0001011010101110","marks":"1","difficulty":"3"},{"id":"objective>Computer Studies>2024>14","subject":"Computer Studies","year":"2024","type":"Objective","topic":"BASIC COMPUTING : COMPONENTS OF COMPUTERS","question":"The part labelled Q in Figure 3 is called","images":["data:image/jpeg;base64,"],"options":{"A":"control unit","B":"data bus","C":"memory unit","D":"register"},"answer":"D","explanation":"A register is a small, high-speed storage unit within a computer's central processing unit (CPU) that is used to hold data temporarily during calculations or other operations. Registers are made up of a series of flip-flops, which are electronic circuits that can store a single bit of data (0 or 1).","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2024>15","subject":"Computer Studies","year":"2024","type":"Objective","topic":"TOOLS FOR PROCESSING INFORMATION : DATABASE MANAGEMENT SYSTEM","question":"MS Access is an example of","images":[],"options":{"A":"word processing package","B":"spreadsheet application","C":"graphic software","D":"database management system"},"answer":"D","explanation":"Microsoft Access (MS Access) is a database management system (DBMS) that allows users to create, design, and manage databases. It provides a graphical interface to create tables, forms, queries, and reports, making it a powerful tool for managing and analyzing data.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2024>16","subject":"Computer Studies","year":"2024","type":"Objective","topic":"TOOLS FOR PROCESSING INFORMATION : OPERATING SYSTEM","question":"Which of the following statements explains the function of device drivers? They","images":[],"options":{"A":"convert source code to object code.","B":"enable hardware and software control and manage the system","C":"help to clean disk space and manage","D":"help to improve the functionality of hardware devices"},"answer":"D","explanation":"Device drivers are software components that allow hardware devices to communicate with the operating system and other software applications. They act as translators between the hardware and software, enabling the hardware to function properly and providing features such as:    - Controlling hardware operations  - Managing data transfer between hardware and software  - Providing hardware-specific functionality  - Enhancing hardware performance","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2024>17","subject":"Computer Studies","year":"2024","type":"Objective","topic":"TOOLS FOR PROCESSING INFORMATION : OPERATING SYSTEM","question":"One usefulness of utility software in the computer is","images":[],"options":{"A":"conversion of source code to object code","B":"enhancement of communication between hardware and the computer system","C":"removal of malware from the computer","D":"to improve the functionality of hardware devices"},"answer":"C","explanation":"Utility software refers to programs that perform maintenance, optimization, and other tasks to keep a computer running smoothly. Some common examples of utility software include:    - Antivirus programs (e.g., Norton Antivirus) that remove malware and protect against future infections  - Disk cleanup tools (e.g., CCleaner) that free up space on the hard drive  - Disk formatting tools (e.g., fdisk) that prepare hard drives for use  - System monitoring tools (e.g., Task Manager) that display system performance and resource usage","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2024>18","subject":"Computer Studies","year":"2024","type":"Objective","topic":"TOOLS FOR PROCESSING INFORMATION : OPERATING SYSTEM","question":"Which of the following statements about operating systems is false? It","images":[],"options":{"A":"enhances the booting process","B":"manages computer devices","C":"manages storage location","D":"protects the computer from storage"},"answer":"D","explanation":"Operating systems (OS) perform various functions, including:    - Managing computer devices (C)  - Managing storage locations (C)  - Enhancing the booting process (A)  - Providing security features to protect the computer from malware, unauthorized access, and other threats (but not specifically from storage)    The correct statement would be \"protects the computer from malware and unauthorized access\", but not \"from storage\".    Storage refers to the hardware components that store data, such as hard drives, solid-state drives, and flash drives. Operating systems manage storage locations, but they do not protect the computer from storage itself.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2024>19","subject":"Computer Studies","year":"2024","type":"Objective","topic":"DEVELOPING PROBLEM-SOLVING SKILLS : PROGRAMMING LANGUAGE (PL)","question":"Debugging in program development is the process of","images":[],"options":{"A":"fixing errors","B":"Introducing bugs","C":"removing virus","D":"writing error messages"},"answer":"A","explanation":"Debugging is the process of identifying, isolating, and fixing errors or bugs in a program or software. It involves:    - Finding the source of the error  - Understanding the cause of the error  - Correcting the error  - Testing the program to ensure the error is resolved    Debugging is an essential step in the program development process, ensuring that the software runs correctly, efficiently, and reliably.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2024>20","subject":"Computer Studies","year":"2024","type":"Objective","topic":"DEVELOPING PROBLEM-SOLVING SKILLS : PROGRAMMING LANGUAGE (PL)","question":"Figure 4 is a flowchart symbol. Use it to answer questions 20 and 21        Identify the flowchart symbol in Figure 4","images":["data:image/jpeg;base64,"],"options":{"A":"Decision box","B":"Manual input","C":"Preparation","D":"Process"},"answer":"A","explanation":"In flowcharts, the symbol used for a decision box is a diamond.    A diamond represents a decision point where the flow can branch based on a \"yes/no\" or \"true/false\" question.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2024>21","subject":"Computer Studies","year":"2024","type":"Objective","topic":"DEVELOPING PROBLEM-SOLVING SKILLS : PROGRAMMING LANGUAGE (PL)","question":"Figure 4 is a flowchart symbol. Use it to answer questions 20 and 21      The flowchart symbol in Figure 4 is used to","images":["data:image/jpeg;base64,"],"options":{"A":"show the preparation stage","B":"represent a decision-making point","C":"input data manually in a flowchart","D":"execute a process"},"answer":"B","explanation":"The flowchart symbol represent a decision-making point.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2024>22","subject":"Computer Studies","year":"2024","type":"Objective","topic":"DEVELOPING PROBLEM-SOLVING SKILLS : PROGRAMMING LANGUAGE (PL)","question":"Which of the following operations will be executed last in a program","images":[],"options":{"A":"Addition","B":"Division","C":"Exponentiation","D":"Subtraction"},"answer":"D","explanation":"In programming, the order of operations follows the standard mathematical precedence rules, often remembered by the acronym PEMDAS (Parentheses, Exponents, Multiplication and Division, Addition and Subtraction).","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2024>23","subject":"Computer Studies","year":"2024","type":"Objective","topic":"DEVELOPING PROBLEM-SOLVING SKILLS : PROGRAMMING LANGUAGE (PL)","question":"The equation x = p + q(r &#247;  s) can be expressed in QBASIC programming as","images":[],"options":{"A":"X = P + Q * (RS)","B":"X = P + Q * (R/S)","C":"X = P + Q (R/S)","D":"X = P + Q (RS)"},"answer":"B","explanation":"The equation x = p + q(r \u00f7 s) can be expressed in QBASIC programming as:    X = P + Q * (R/S)","marks":"1","difficulty":"3"},{"id":"objective>Computer Studies>2024>24","subject":"Computer Studies","year":"2024","type":"Objective","topic":"DEVELOPING PROBLEM-SOLVING SKILLS : PROGRAMMING LANGUAGE (PL)","question":"Which of the following statements is true about the rules of flowcharting?","images":[],"options":{"A":"All boxes of flowcharts are connected with arrows to show the logical connection between them","B":"All flowchart process boxes are connected with on page connector to show the flow of operation","C":"All flowcharts start with a start box and end with a decision box","D":"The flow of control must always enter an object from bottom to top"},"answer":"A","explanation":"All boxes of flowcharts are connected with arrows to show the logical connection between them.    Flowcharting rules:    - Use standardized symbols (e.g., rectangles, diamonds, ovals)  - Connect symbols with arrows to show logical connections and flow  - Use one entry and one exit point (except for loops)  - Avoid crossing arrows or lines  - Keep it simple, clear, and concise","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2024>25","subject":"Computer Studies","year":"2024","type":"Objective","topic":"DEVELOPING PROBLEM-SOLVING SKILLS : PROGRAMMING LANGUAGE (PL)","question":"In computer programming, it is advised to translate source code into intermediate code to","images":[],"options":{"A":"change the analysis portion for different compilers","B":"ensure that full native compiler is used for every new machine that will run the program","C":"make it easier to apply the source code modifications to improve code performance","D":"make the synthesis part of the compiler target-machine dependent"},"answer":"D","explanation":"In compiler design:    Intermediate code is used to create a machine-independent layer between the source code and the final machine code.    Analysis (or the front-end) of the compiler, which includes tasks like lexical analysis, parsing, and semantic analysis, produces this intermediate code. This part is machine-independent, meaning it doesn't need to change for different target machines.    The synthesis (or the back-end) of the compiler then takes this intermediate code and translates it into machine code specific to the target machine. This part is machine-dependent.    The use of intermediate code allows the front-end of the compiler to remain consistent across different platforms, while the back-end (synthesis) is adapted to generate machine-specific code.    So, the correct answer (\"make the synthesis part of the compiler target-machine dependent\") refers to the fact that the synthesis, or the code generation phase, is tailored to the specific machine, while the analysis part remains independent of the machine.","marks":"1","difficulty":"3"},{"id":"objective>Computer Studies>2024>26","subject":"Computer Studies","year":"2024","type":"Objective","topic":"INFORMATION TRANSMISSION : INTERNET","question":"A graphic or text in a document or webpage that links to another file or object is referred to as","images":[],"options":{"A":"a domain name","B":"a hyperlink","C":"a shortcut","D":"an icon"},"answer":"B","explanation":"A hyperlink is a graphic or text in a document or webpage that links to another file, object, or webpage. It allows users to click on the link to access the connected resource. Hyperlinks are a fundamental feature of the internet, enabling navigation between web pages and access to related information.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2024>27","subject":"Computer Studies","year":"2024","type":"Objective","topic":"INFORMATION TRANSMISSION : MEDIUM OF INFORMATION TRANSMISSION","question":"Instant messages can be sent with little or no time lag using","images":[],"options":{"A":"podcast","B":"facsimile","C":"email","D":"chat room"},"answer":"D","explanation":"Chat rooms, also known as instant messaging (IM) or real-time messaging, allow users to send text messages in real-time, with little to no time lag. This enables instantaneous communication and conversation.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2024>28","subject":"Computer Studies","year":"2024","type":"Objective","topic":"ETHICS AND HUMAN ISSUES : SAFETY MEASURES","question":"Which of the following statements is true about preventing phishing","images":[],"options":{"A":"Ensure that antivirus is updated regularly","B":"Do not click on links in emails from untrusted sources","C":"Do not download from untrusted sites","D":"Use a strong password at all times"},"answer":"B","explanation":"Do not click on links in emails from untrusted sources.    Phishing is a type of cybercrime that involves tricking individuals into revealing sensitive information such as passwords, credit card numbers, or other personal information. To prevent phishing, it's essential to:    - Be cautious with links in emails from untrusted sources  - Verify the authenticity of emails before taking any action  - Use two-factor authentication whenever possible  - Keep software and security up to date (including antivirus)","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2024>29","subject":"Computer Studies","year":"2024","type":"Objective","topic":"INFORMATION TRANSMISSION : NETWORKING","question":"Which of the following statements is true about star topologies?","images":[],"options":{"A":"Computers are connected node-to-node","B":"Computers are connected to a central device","C":"The connection is linear in shape","D":"The connection is a tree-like structure"},"answer":"B","explanation":"Computers are connected to a central device.    In a star topology, all devices (computers, nodes, etc.) are connected to a central device, such as a hub, switch, or router. This central device acts as a connection point for all the other devices, and all data transmission goes through it.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2024>30","subject":"Computer Studies","year":"2024","type":"Objective","topic":"DATA MANAGEMENT : DATABASE SECURITY","question":"An internet user secures his social media account by regularly changing passwords. Which of the following passwords produces the best security?","images":[],"options":{"A":"wasscesc2024","B":"WASSCESC2024","C":"2024wasscesc","D":"WASSCESchoolCandidates@2024"},"answer":"D","explanation":"The correct answer is WASSCESchoolCandidates@2024.    This password is the strongest because it:    - Is long (over 12 characters)  - Contains a mix of:      - Uppercase letters (W, S, C)      - Lowercase letters (s, c, h, o, o, l)      - Numbers (2, 0, 2, 4)      - Special characters (@)  - Does not contain personal information (name, birthdate, etc.)  - Does not contain common words or phrases  - Is not a variation of a previous password","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2024>31","subject":"Computer Studies","year":"2024","type":"Objective","topic":"INFORMATION TRANSMISSION : NETWORKING","question":"Which of the following statements is true about intranet?","images":[],"options":{"A":"Private network that uses internet protocol and is accessible by all visitors to an organization's website","B":"Private network that uses internet protocol and is accessible by employees of an organization","C":"Private network which does not use internet protocol and is accessible by employees of an organization","D":"Public network that uses internet protocol and is accessible by all visitors to an organization's website"},"answer":"B","explanation":"Private network that uses Internet protocol and is accessible by employees of an organisation.    An intranet is a private network that uses Internet protocols (TCP/IP, HTTP, etc.) to share information and resources within an organization. It is accessible only to authorized employees, partners, or stakeholders, and is not publicly accessible through the Internet.    Intranets are used for various purposes, such as:    - Sharing company information and news  - Collaborating on projects and documents  - Providing access to company resources and tools  - Facilitating communication and feedback","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2024>32","subject":"Computer Studies","year":"2024","type":"Objective","topic":"TOOLS FOR PROCESSING INFORMATION : WORD PROCESSING","question":"The art of checking for errors in a Word Document before publishing is referred to as","images":[],"options":{"A":"editing","B":"formatting","C":"modifying","D":"proof reading"},"answer":"D","explanation":"Proofreading is the process of carefully reviewing a document, such as a Word document, for errors in:    - Spelling  - Grammar  - Punctuation  - Syntax  - Formatting  - Consistency    before publishing or sharing it. The goal of proofreading is to ensure that the document is error-free, accurate, and polished.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2024>33","subject":"Computer Studies","year":"2024","type":"Objective","topic":"TOOLS FOR PROCESSING INFORMATION : DATABASE MANAGEMENT SYSTEM","question":"Columns in MS Access are referred to as","images":[],"options":{"A":"Fields","B":"Files","C":"Records","D":"Tuples"},"answer":"A","explanation":"In Microsoft Access, columns in a table are referred to as Fields. Fields define the structure of a table and represent a single aspect of the data being stored, such as \"Employee ID\", \"Name\", \"Department\", etc.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2024>34","subject":"Computer Studies","year":"2024","type":"Objective","topic":"TOOLS FOR PROCESSING INFORMATION : SPREADSHEET","question":"Which of the following application packages is suitable for making budgets","images":[],"options":{"A":"Word Processor","B":"Spreadsheet package","C":"Graphic package","D":"Database Management System"},"answer":"B","explanation":"A spreadsheet package, such as Microsoft Excel or Google Sheets, is ideal for creating budgets because it allows you to:    - Enter and manipulate numerical data  - Perform calculations and formulas  - Create tables and charts to visualize data  - Easily update and modify data    Spreadsheet software is designed for numerical analysis and data management, making it perfect for budgeting, financial planning, and data analysis.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2024>35","subject":"Computer Studies","year":"2024","type":"Objective","topic":"TOOLS FOR PROCESSING INFORMATION : SPREADSHEET","question":"What happens when a user clicks on the icon in Figure 5 in the Microsoft Excel Menu Bar?","images":["data:image/jpeg;base64,"],"options":{"A":"A copy of the selection is put on the clipboard so that user can paste it somewhere else","B":"A label that spans multiple columns is created","C":"Content on the clipboard is added to the document","D":"Selected range of cells is quickly converted to a table with its own style"},"answer":"C","explanation":"The Paste icon in Excel is a clipboard symbol, often represented by a clipboard with a sheet of paper on it. It is used to insert copied or cut data into a selected cell or range of cells.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2024>36","subject":"Computer Studies","year":"2024","type":"Objective","topic":"TOOLS FOR PROCESSING INFORMATION : SPREADSHEET","question":"New Comment can be added to a cell in MS Excel using","images":[],"options":{"A":"Edit &#8594; Comment","B":"File &#8594; Comment","C":"Insert &#8594; Comment","D":"Review &#8594; Comment"},"answer":"D","explanation":"To add a new comment to a cell in MS Excel, you can follow these steps:    1. Select the cell where you want to add the comment.  2. Go to the Review tab in the ribbon.  3. Click on the \"New Comment\" button in the \"Comments\" group.  4. Type your comment in the text box that appears.    Alternatively, you can also right-click on the cell and select \"Insert Comment\" from the context menu.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2024>37","subject":"Computer Studies","year":"2024","type":"Objective","topic":"TOOLS FOR PROCESSING INFORMATION : GRAPHIC PACKAGES","question":"What is the function of the CorelDraw Toolbox object shown in Figure 6? It is used to","images":["data:image/jpeg;base64,"],"options":{"A":"change the magnification level in drawing window","B":"draw lines and curves","C":"edit the shape of objects","D":"select and transform objects"},"answer":"D","explanation":"The move tool in CorelDRAW is a powerful and versatile tool that allows you to select, move, resize, rotate, and apply various transformations to objects in your design. It's a combination of several tools, making it a convenient one-stop solution for many common tasks.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2024>38","subject":"Computer Studies","year":"2024","type":"Objective","topic":"TOOLS FOR PROCESSING INFORMATION : DATABASE MANAGEMENT SYSTEM","question":"Which of the following statements about index is true? It is a data structure","images":[],"options":{"A":"that reduces the speed of data retrieval operations on a database table","B":"used to quickly locate data without searching every row in a table every time a database table is accessed","C":"created using only two rows of a database table to uniquely identify each record","D":"that allows relational database to split and store data in different tables while linking disparate items"},"answer":"B","explanation":"It is a data structure that enables quick location of data without searching every row in a table every time a database table is accessed.    This statement is true because an index in a database allows for fast lookup and retrieval of data without having to scan the entire table, making queries more efficient.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2024>39","subject":"Computer Studies","year":"2024","type":"Objective","topic":"BASIC COMPUTING : COMPONENTS OF COMPUTERS","question":"A collection of computer wires used to identify memory location in a computer is","images":[],"options":{"A":"system bus","B":"data bus","C":"data cable","D":"address bus"},"answer":"D","explanation":"An address bus is a collection of computer wires used to identify memory locations in a computer. It carries the addresses of memory locations that the CPU (Central Processing Unit) wants to access, allowing the computer to retrieve or store data in the corresponding memory locations.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2024>40","subject":"Computer Studies","year":"2024","type":"Objective","topic":"BASIC COMPUTING : COMPONENTS OF COMPUTERS","question":"Read Only Memory (ROM) contains","images":[],"options":{"A":"current program in operation","B":"preset instructions for operation","C":"user instructions","D":"volatile programs"},"answer":"B","explanation":"ROM (Read-Only Memory) contains permanent, preset instructions that are programmed during the manufacturing process and cannot be changed or written by a user. These instructions are used to control the basic operation of a computer or device, such as the BIOS (Basic Input/Output System) in a computer.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2024>41","subject":"Computer Studies","year":"2024","type":"Objective","topic":"DATA MANAGEMENT : FILE ORGANIZATION","question":"What happens when the Shift key is pressed down while deleting a file from the computer. The file is","images":[],"options":{"A":"Uninstalled from the computer","B":"permanently deleted from the computer","C":"deleted and sent to the Recycle Bin","D":"deleted and kept in the clipboard"},"answer":"B","explanation":"When you press the Shift key while deleting a file (by clicking \"Delete\" or pressing \"Delete\" on your keyboard), the file will be permanently deleted from your computer, bypassing the Recycle Bin. This means that the file will not be moved to the Recycle Bin, where it can be recovered, but will instead be immediately removed from your system.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2024>42","subject":"Computer Studies","year":"2024","type":"Objective","topic":"TOOLS FOR PROCESSING INFORMATION : OPERATING SYSTEM","question":"Which of the following statements about warm booting is true? The computer","images":[],"options":{"A":"reloads the operating system while still running in the background","B":"loads the operating system into memory from the power-on button","C":"reloads the operating system into memory while still loading","D":"loads the application into memory from rest state"},"answer":"A","explanation":"Reloads the operating system while still running in the background.    Warm booting, also known as soft booting, is the process of restarting a computer without turning off the power. This means that the computer's operating system is reloaded while the computer is still running, without going through the full shutdown and startup process.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2024>43","subject":"Computer Studies","year":"2024","type":"Objective","topic":"INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING","question":"The  ASCII  character set that represents alphabetical and control characters using numeric code ranges from","images":[],"options":{"A":"0 to 32","B":"0 to 64","C":"0 to 127","D":"0 to 128"},"answer":"C","explanation":"ASCII (American Standard Code for Information Interchange) is a character encoding standard that represents alphabetical, numerical, and control characters using numeric codes. The ASCII character set ranges from 0 to 127, inclusive.    - 0 to 31: Control characters (e.g., tab, newline, bell)  - 32 to 126: Printable characters (letters, digits, punctuation marks, etc.)  - 127: Delete character (a special control character)","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2024>44","subject":"Computer Studies","year":"2024","type":"Objective","topic":"INFORMATION AGE : DATA AND INFORMATION","question":"Which of the following hard disk drive memory capacities can store the largest size of data","images":[],"options":{"A":"2 TB","B":"12 GB","C":"240 MB","D":"800 KB"},"answer":"A","explanation":"2TB can store the largest size of data among the given options.    Here's a breakdown of the units:    Terabyte (TB): The largest unit among the options, representing 1 trillion bytes. \u00a0   Gigabyte (GB): 1 billion bytes. \u00a0   Megabyte (MB): 1 million bytes. \u00a0   Kilobyte (KB): 1 thousand bytes. \u00a0     Therefore, 2TB is the largest storage capacity.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2024>45","subject":"Computer Studies","year":"2024","type":"Objective","topic":"INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING","question":"The equivalent of the letter A in the standard ASCII is","images":[],"options":{"A":"01000001","B":"01000010","C":"01100001","D":"01100010"},"answer":"A","explanation":"In the standard ASCII (American Standard Code for Information Interchange) character set, the letter \"A\" is represented by the binary code 01100001.    Here's a brief explanation:    - ASCII uses 7-bit binary codes to represent characters.  - The letter \"A\" is the 65th character in the ASCII table.  - The binary representation of 65 in 7-bit form is 01100001.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2024>46","subject":"Computer Studies","year":"2024","type":"Objective","topic":"TOOLS FOR PROCESSING INFORMATION : DATABASE MANAGEMENT SYSTEM","question":"One example of a file containing reference data which is usually altered is","images":[],"options":{"A":"brand name","B":"payroll","C":"price list","D":"stock"},"answer":"C","explanation":"A price list is a type of reference data file that is commonly updated or altered as prices change over time. It contains a list of items or services with their corresponding prices, and is often used in business and commerce.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2024>47","subject":"Computer Studies","year":"2024","type":"Objective","topic":"INFORMATION TRANSMISSION : MEDIUM OF INFORMATION TRANSMISSION~~INFORMATION TRANSMISSION : PROCESS OF INFORMATION TRANSMISSION","question":"Figure 7 represents a procedure to","images":["data:image/jpeg;base64,"],"options":{"A":"backup files on the computer","B":"repair a corrupted file on a computer","C":"transfer files from one device to another","D":"update software on a device"},"answer":"C","explanation":"The figure represents the procedure of transfer of files through bluetooth from a PC to an Android phone and vice versa.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2024>48","subject":"Computer Studies","year":"2024","type":"Objective","topic":"DATA MANAGEMENT : FILE ORGANIZATION","question":"A user observed that a certain file in a removable storage device changed to a shortcut icon. This implies that","images":[],"options":{"A":"the file is corrupt","B":"the file is shared","C":"the removable storage device is corrupt","D":"there is a link to the file"},"answer":"D","explanation":"When a file icon changes to a shortcut icon, it usually indicates that there's a link (or shortcut) pointing to the original file. This link can be located on the same device or on a different device. The shortcut allows you to quickly access the original file without having to navigate to its actual location.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2024>49","subject":"Computer Studies","year":"2024","type":"Objective","topic":"ETHICS AND HUMAN ISSUES : SAFETY MEASURES","question":"Set of characters used to authenticate a computer user is called","images":[],"options":{"A":"encoder","B":"binary code","C":"password","D":"barcode"},"answer":"C","explanation":"A password is a set of characters used to authenticate a computer user, providing secure access to a computer system, network, or application. Passwords are typically a combination of letters, numbers, and special characters that only the authorized user knows.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2024>50","subject":"Computer Studies","year":"2024","type":"Objective","topic":"INFORMATION TRANSMISSION : INTERNET~~INFORMATION TRANSMISSION : NETWORKING","question":"Which of the following statements about firewall is correct","images":[],"options":{"A":"A network transmission system that increases the speed of incoming and outgoing network traffic","B":"A network security system that establishes a barrier between a trusted internal network and an untrusted external network such as the Internet","C":"A data structure that improves the speed of data retrieval operations on a database table","D":"A data structure created using only two rows of a database table used to uniquely identify each record"},"answer":"B","explanation":"A network security system that establishes a barrier between a trusted internal network and an untrusted external network, such as the Internet.    A firewall is a network security system that monitors and controls incoming and outgoing network traffic based on predetermined security rules. It acts as a barrier between a trusted internal network (such as a company's internal network) and an untrusted external network (such as the Internet). This helps to prevent unauthorized access, block malicious traffic, and protect the internal network from potential threats.","marks":"1","difficulty":"2"}];